registerModule('Pixel Glow Effect', function(g) {
  g._glow = g._glow || { pulse: 0, trails: [] };

  var glow = g._glow;
  var ctx = g.ctx;

  // Advance pulse oscillator
  glow.pulse = (glow.pulse + 0.05) % (Math.PI * 2);

  // Store trail positions (ring buffer style)
  if (g.tick % 2 === 0) {
    glow.trails.push({ x: g.px, y: g.py, age: 0 });
    if (glow.trails.length > 12) glow.trails.shift();
  }

  // Draw motion trails
  for (var i = 0; i < glow.trails.length; i++) {
    var t = glow.trails[i];
    t.age++;
    var trailAlpha = Math.max(0, 0.35 - t.age * 0.03);
    var trailSize = Math.max(0, 6 - t.age * 0.4);
    if (trailAlpha <= 0 || trailSize <= 0) continue;

    var trailGrad = ctx.createRadialGradient(t.x, t.y, 0, t.x, t.y, trailSize);
    trailGrad.addColorStop(0, 'rgba(0,255,170,' + trailAlpha + ')');
    trailGrad.addColorStop(1, 'rgba(0,255,170,0)');
    ctx.beginPath();
    ctx.arc(t.x, t.y, trailSize, 0, Math.PI * 2);
    ctx.fillStyle = trailGrad;
    ctx.fill();
  }

  // Pulsing outer glow radius
  var pulseVal = 0.5 + 0.5 * Math.sin(glow.pulse);
  var glowRadius = 18 + pulseVal * 8;
  var glowAlpha  = 0.18 + pulseVal * 0.12;

  // Outer ambient glow
  var outerGrad = ctx.createRadialGradient(g.px, g.py, 0, g.px, g.py, glowRadius);
  outerGrad.addColorStop(0,   'rgba(0,255,170,' + (glowAlpha * 1.8).toFixed(3) + ')');
  outerGrad.addColorStop(0.4, 'rgba(0,220,150,' + glowAlpha.toFixed(3) + ')');
  outerGrad.addColorStop(1,   'rgba(0,255,170,0)');

  ctx.beginPath();
  ctx.arc(g.px, g.py, glowRadius, 0, Math.PI * 2);
  ctx.fillStyle = outerGrad;
  ctx.fill();

  // Inner bright core halo
  var coreRadius = 5 + pulseVal * 2;
  var coreGrad = ctx.createRadialGradient(g.px, g.py, 0, g.px, g.py, coreRadius);
  coreGrad.addColorStop(0, 'rgba(180,255,230,0.95)');
  coreGrad.addColorStop(0.3, 'rgba(0,255,170,0.7)');
  coreGrad.addColorStop(1, 'rgba(0,255,170,0)');

  ctx.beginPath();
  ctx.arc(g.px, g.py, coreRadius, 0, Math.PI * 2);
  ctx.fillStyle = coreGrad;
  ctx.fill();

  // Sparkle rays — thin lines radiating outward
  var rayCount = 6;
  var rayOffset = glow.pulse * 0.4;
  ctx.save();
  ctx.globalAlpha = 0.15 + pulseVal * 0.1;
  ctx.strokeStyle = '#00ffaa';
  ctx.lineWidth = 0.5;
  for (var r = 0; r < rayCount; r++) {
    var angle = (r / rayCount) * Math.PI * 2 + rayOffset;
    var innerR = 3;
    var outerR = 12 + pulseVal * 6;
    ctx.beginPath();
    ctx.moveTo(g.px + Math.cos(angle) * innerR, g.py + Math.sin(angle) * innerR);
    ctx.lineTo(g.px + Math.cos(angle) * outerR, g.py + Math.sin(angle) * outerR);
    ctx.stroke();
  }
  ctx.restore();
})

